mapper.select:
SELECT * FROM rsi_analysis 
ORDER BY data_time DESC
LIMIT #{limit}

mapper.delete:
DELETE FROM rsi_analysis 
WHERE code = #{code} AND period = #{period}
AND id NOT IN (
    SELECT id FROM (
        SELECT id FROM rsi_analysis 
        WHERE code = #{code} AND period = #{period}
        ORDER BY data_time DESC 
        LIMIT #{keepCount}
    ) tmp
)
